-- pgAdmin: mở Query Tool trên database review_db rồi chạy toàn bộ file này.
CREATE TABLE IF NOT EXISTS reviews(id varchar(40) PRIMARY KEY,content_id varchar(160) NOT NULL,profile_id varchar(40) NOT NULL,profile_name varchar(80) NOT NULL,rating smallint NOT NULL CHECK(rating BETWEEN 1 AND 5),comment text NOT NULL DEFAULT '',is_spoiler boolean NOT NULL DEFAULT false,like_count int NOT NULL DEFAULT 0,created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now(),UNIQUE(content_id,profile_id));
ALTER TABLE reviews ALTER COLUMN content_id TYPE varchar(160);
CREATE TABLE IF NOT EXISTS review_reactions(review_id varchar(40) NOT NULL REFERENCES reviews(id) ON DELETE CASCADE,profile_id varchar(40) NOT NULL,reaction varchar(10) NOT NULL CHECK(reaction IN('like','dislike')),created_at timestamptz NOT NULL DEFAULT now(),PRIMARY KEY(review_id,profile_id));
CREATE INDEX IF NOT EXISTS idx_reviews_content_rank ON reviews(content_id,like_count DESC,created_at DESC);
